const { message, branchId, role, userName } = $json;

const userRole = (role || 'owner').toLowerCase();
const userBranch = branchId || 1;
const userNameClean = userName || 'Owner';

let msg = (message || '').toLowerCase().trim();

// ===== NORMALISASI BAHASA INDONESIA =====
// Hapus salam sapaan
msg = msg.replace(/^(halo|hallo|helo|hi|hey|hai|siang|pagi|sore|malam|permisi|misi|maaf|bro|bang|kak|tolong|bantu|coba|test|tes)\b[\s,]*/gi, '');

// Hapus pengulangan identitas (sudah ada di context)
msg = msg.replace(/(saya|aku|gw|gue)\s+(owner|adalah|pemilik|admin)\b[\s,]*/gi, '');
msg = msg.replace(/\bcabang\s*(id\s*)?\d+\b[\s,]*/gi, '');
msg = msg.replace(/\bbranch\s*(id\s*)?\d+\b[\s,]*/gi, '');

// Normalisasi frasa umum
const replacements = {
  'sikit': 'sedikit',
  'dikit': 'sedikit',
  'abis': 'habis',
  'abiz': 'habis',
  'cek': 'lihat',
  'cekidot': 'lihat',
  'check': 'lihat',
  'nambah': 'tambah',
  'nmbah': 'tambah',
  'nmbh': 'tambah',
  'bikin': 'buat',
  'bikinin': 'buat',
  'produk': 'produk',
  'menu': 'produk',
  'produksi': 'produksi',
  'produsi': 'produksi',
  'stok': 'stok',
  'stock': 'stok',
  'bahan': 'bahan',
  'bhn': 'bahan',
  'bhn baku': 'bahan baku',
  'pengeluaran': 'pengeluaran',
  'belanja': 'pengeluaran',
  'biaya': 'pengeluaran',
  'laporan': 'laporan',
  'report': 'laporan',
  'revenue': 'pendapatan',
  'profit': 'keuntungan',
  'untung': 'keuntungan',
  'rugi': 'kerugian',
};
for (const [key, val] of Object.entries(replacements)) {
  const regex = new RegExp('\\b' + key + '\\b', 'gi');
  msg = msg.replace(regex, val);
}

// Peta intent ke perintah teknis
const intentMap = [
  { pattern: /lihat stok menipis|stok (habis|sedikit|menipis|kritis|tipis)|bahan (habis|sedikit|menipis)/, intent: 'INTENT: CEK_STOK_MENIPIS' },
  { pattern: /lihat (bahan baku|bahan|ingredient)|daftar bahan/, intent: 'INTENT: LIHAT_BAHAN' },
  { pattern: /tambah (bahan|bahan baku|ingredient)/, intent: 'INTENT: TAMBAH_BAHAN' },
  { pattern: /stok (masuk|in|tambah)|tambah stok/, intent: 'INTENT: STOK_MASUK' },
  { pattern: /stok (keluar|out|kurang)|kurang stok/, intent: 'INTENT: STOK_KELUAR' },
  { pattern: /produksi|produk (jadi|setengah jadi)|bikin|buat (stok|produk)/, intent: 'INTENT: PRODUKSI' },
  { pattern: /lihat (produk|menu|produk menu)/, intent: 'INTENT: LIHAT_PRODUK' },
  { pattern: /tambah (produk|menu)/, intent: 'INTENT: TAMBAH_PRODUK' },
  { pattern: /lihat (resep|bom|recipe)/, intent: 'INTENT: LIHAT_RESEP' },
  { pattern: /catat (pengeluaran|biaya|belanja)/, intent: 'INTENT: CATAT_PENGELUARAN' },
  { pattern: /laporan (keuangan|finansial)|lihat (laporan|keuangan|pendapatan|keuntungan)/, intent: 'INTENT: LAPORAN_KUANGAN' },
];

let detectedIntent = '';
for (const entry of intentMap) {
  if (entry.pattern.test(msg)) {
    detectedIntent = entry.intent;
    break;
  }
}

// Bersihkan spasi berlebih
msg = msg.replace(/\s+/g, ' ').trim();

// Jika pesan kosong setelah normalisasi, pakai aslinya (kasih tau user)
if (!msg) {
  msg = (message || '').trim();
}

const prefix = detectedIntent ? detectedIntent + '\n' : '';
const context = 'USER: ' + userNameClean + ' | ROLE: ' + userRole + ' | BRANCH: ' + userBranch + '\n';
const fullMessage = context + prefix + msg;

return [{ json: { message: fullMessage, detectedIntent, userBranch } }];

